from flask import Flask, redirect, url_for, request, session
import requests
import json
from urllib.parse import urlencode

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your_secret_key_here'

# OpenID Connect provider configuration
oidc_provider_config = {
    'issuer': 'https://your-oidc-provider.com',
    'authorization_endpoint': 'https://your-oidc-provider.com/authorize',
    'token_endpoint': 'https://your-oidc-provider.com/token'
}

@app.route('/')
def index():
    return redirect(url_for('login'))

@app.route('/login')
def login():
    auth_params = {
        'client_id': 'your_client_id_here',
        'redirect_uri': url_for('callback', _external=True),
        'response_type': 'id_token',
        'scope': 'openid'
    }
    return redirect(oidc_provider_config['authorization_endpoint'] + '?' + urlencode(auth_params))

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if not code:
        return 'Error: No authorization code provided', 400

    # Validate the client ID and redirect URI
    auth_params = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': url_for('callback', _external=True),
        'client_id': oidc_provider_config['client_id']
    }

    token_response = requests.post(
        oidc_provider_config['token_endpoint'],
        headers={'Content-Type': 'application/x-www-form-urlencoded'},
        data=urlencode(auth_params)
    )

    if token_response.status_code != 200:
        return 'Error: Failed to obtain access token', 500

    token_data = json.loads(token_response.text)
    id_token = token_data['id_token']

    # Validate the ID token
    try:
        from pyjwt import decode as jwt_decode
        payload = jwt_decode(id_token, verify=True)
    except Exception as e:
        return 'Error: Invalid ID token', 401

    session['user'] = payload
    return redirect(url_for('protected'))

@app.route('/protected')
def protected():
    if 'user' in session:
        return 'Hello, authenticated user!'
    else:
        return 'Error: Not authorized', 403

if __name__ == '__main__':
    app.run(debug=True)